import{_ as t}from"./chunks/文件受限图.DsG20F9s.js";import{_ as e,o as l,c as i,a2 as r}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"圖片審查與存取模式","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/Safety/image-moderation-and-access-mode.md","filePath":"zh-TW/Safety/image-moderation-and-access-mode.md","lastUpdated":1781962217000}'),d={name:"zh-TW/Safety/image-moderation-and-access-mode.md"};function o(h,a,p,n,s,c){return l(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="圖片審查與存取模式" tabindex="-1">圖片審查與存取模式 <a class="header-anchor" href="#圖片審查與存取模式" aria-label="Permalink to &quot;圖片審查與存取模式&quot;">​</a></h1><p>「圖片審查」用來替上傳圖片設定年齡分級，並透過「存取模式」控制公開訪問時能看到哪些內容。</p><p>這個設定會影響公開圖庫、公開 URL 連結和隨機圖 API。後台管理頁不受這個存取模式限制，管理員仍然可以查看和管理全部檔案。</p><h2 id="功能入口" tabindex="-1">功能入口 <a class="header-anchor" href="#功能入口" aria-label="Permalink to &quot;功能入口&quot;">​</a></h2><p>進入後台後打開：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>系統設定 -&gt; 安全設定 -&gt; 上傳管理 -&gt; 圖片審查</span></span></code></pre></div><p>主要有三個設定：</p><ul><li>存取模式</li><li>啟用審查</li><li>審查渠道</li></ul><h2 id="存取模式是做什麼的" tabindex="-1">存取模式是做什麼的 <a class="header-anchor" href="#存取模式是做什麼的" aria-label="Permalink to &quot;存取模式是做什麼的&quot;">​</a></h2><p>存取模式決定公開訪問時允許顯示到哪個年齡分級。</p><p>目前有四種：</p><table tabindex="0"><thead><tr><th>存取模式</th><th>公開可見範圍</th></tr></thead><tbody><tr><td>成人模式</td><td>全年齡、R12、R16、R18</td></tr><tr><td>青年模式</td><td>全年齡、R12、R16</td></tr><tr><td>少年模式</td><td>全年齡、R12</td></tr><tr><td>兒童模式</td><td>僅全年齡</td></tr></tbody></table><p>預設是成人模式。</p><p>如果站台自用或成人內容較多，可以維持成人模式。如果希望公開圖庫更保守，可以改成青年、少年或兒童模式。</p><h2 id="啟用審查是做什麼的" tabindex="-1">啟用審查是做什麼的 <a class="header-anchor" href="#啟用審查是做什麼的" aria-label="Permalink to &quot;啟用審查是做什麼的&quot;">​</a></h2><p>啟用審查後，系統會在上傳時呼叫你選擇的審查渠道，辨識圖片並寫入年齡分級。</p><p>分級主要有：</p><table tabindex="0"><thead><tr><th>分級</th><th>含義</th></tr></thead><tbody><tr><td>全年齡</td><td>一般公開內容</td></tr><tr><td>R12</td><td>輕度敏感內容</td></tr><tr><td>R16</td><td>中度敏感內容</td></tr><tr><td>R18</td><td>成人內容</td></tr></tbody></table><p>審查結果會參與公開存取判斷。</p><p>如果沒有啟用審查，或某些舊檔案還沒有分級，這些檔案會被視為未分級。未分級檔案不會只因為沒有審查結果，就自動從公開圖庫和隨機圖消失。</p><h2 id="審查渠道怎麼選" tabindex="-1">審查渠道怎麼選 <a class="header-anchor" href="#審查渠道怎麼選" aria-label="Permalink to &quot;審查渠道怎麼選&quot;">​</a></h2><p>目前審查渠道包括：</p><ul><li>moderatecontent.com</li><li>nsfwjs</li><li>Sightengine</li></ul><p>不同渠道需要的設定不同：</p><ul><li>moderatecontent.com 通常需要 API Key。</li><li>nsfwjs 通常需要填 API 端點。</li><li>Sightengine 需要 API User 和 API Secret。</li></ul><p>選哪個渠道取決於你的帳號、服務可用性和辨識效果。只要啟用審查並設定正確，上傳時就會嘗試寫入圖片分級。</p><h2 id="對公開圖庫的影響" tabindex="-1">對公開圖庫的影響 <a class="header-anchor" href="#對公開圖庫的影響" aria-label="Permalink to &quot;對公開圖庫的影響&quot;">​</a></h2><p>公開圖庫列表會依存取模式過濾內容。</p><p>例如：</p><ul><li>成人模式：公開圖庫可以顯示 R18 圖片。</li><li>青年模式：公開圖庫不會顯示 R18 圖片。</li><li>少年模式：公開圖庫不會顯示 R16 和 R18 圖片。</li><li>兒童模式：公開圖庫只顯示全年齡圖片。</li></ul><p>這只影響普通公開訪問。後台管理頁仍可看到全部檔案。</p><h2 id="對公開-url-連結的影響" tabindex="-1">對公開 URL 連結的影響 <a class="header-anchor" href="#對公開-url-連結的影響" aria-label="Permalink to &quot;對公開 URL 連結的影響&quot;">​</a></h2><p>公開 URL 連結就是使用者直接打開圖片連結的情境。</p><p>如果圖片分級在目前存取模式允許範圍內，系統會正常回傳原圖。</p><p>如果圖片分級超過目前存取模式，普通訪問不會回傳原圖，而是回傳攔截結果或提示圖。</p><p>例如：</p><ul><li>目前是兒童模式。</li><li>某張圖是 R18。</li><li>訪客直接打開這張圖的公開連結。</li><li>系統不會把 R18 原圖回傳給普通訪客。</li></ul><p><img src="'+t+'" alt="檔案受限圖" loading="lazy"></p><h2 id="對隨機圖的影響" tabindex="-1">對隨機圖的影響 <a class="header-anchor" href="#對隨機圖的影響" aria-label="Permalink to &quot;對隨機圖的影響&quot;">​</a></h2><p>隨機圖 API 也會依存取模式過濾候選池。</p><p>如果目前是兒童模式，隨機圖只會從全年齡圖片裡抽取。</p><p>如果目前是青年模式，隨機圖可以從全年齡、R12、R16 圖片裡抽取，但不會抽到 R18。</p><h2 id="和名單規則的關係" tabindex="-1">和名單規則的關係 <a class="header-anchor" href="#和名單規則的關係" aria-label="Permalink to &quot;和名單規則的關係&quot;">​</a></h2><p>存取模式不是唯一的公開訪問規則，它會和名單規則一起生效。</p><p>簡單理解：</p><ul><li>白名單內容優先公開。</li><li>黑名單內容普通使用者不能直接看到原圖。</li><li>不在名單裡的內容，再依存取模式判斷是否允許公開。</li></ul><p>如果一張圖片同時被年齡分級和名單規則限制，普通使用者仍不能直接看到原圖。</p><h2 id="建議設定" tabindex="-1">建議設定 <a class="header-anchor" href="#建議設定" aria-label="Permalink to &quot;建議設定&quot;">​</a></h2><p>公開站台建議：</p><ul><li>啟用審查。</li><li>依站台定位選擇存取模式。</li><li>面向全年齡使用者時選兒童模式或少年模式。</li><li>不希望公開展示成人內容時，不要使用成人模式。</li><li>定期檢查後台檔案分級，必要時手動調整。</li></ul><p>私人或自用站台可以：</p><ul><li>使用成人模式。</li><li>視需求啟用審查。</li><li>在後台管理頁查看和調整分級。</li></ul><h2 id="常見問題" tabindex="-1">常見問題 <a class="header-anchor" href="#常見問題" aria-label="Permalink to &quot;常見問題&quot;">​</a></h2><h3 id="改存取模式-後台檔案會消失嗎" tabindex="-1">改存取模式，後台檔案會消失嗎？ <a class="header-anchor" href="#改存取模式-後台檔案會消失嗎" aria-label="Permalink to &quot;改存取模式，後台檔案會消失嗎？&quot;">​</a></h3><p>不會。存取模式只影響普通公開訪問，不影響後台管理頁。</p><h3 id="改成兒童模式後-公開圖庫為什麼少很多圖片" tabindex="-1">改成兒童模式後，公開圖庫為什麼少很多圖片？ <a class="header-anchor" href="#改成兒童模式後-公開圖庫為什麼少很多圖片" aria-label="Permalink to &quot;改成兒童模式後，公開圖庫為什麼少很多圖片？&quot;">​</a></h3><p>因為兒童模式只允許全年齡圖片公開顯示。R12、R16、R18 會被過濾。</p><h3 id="公開-url-還會直接打開成人圖片嗎" tabindex="-1">公開 URL 還會直接打開成人圖片嗎？ <a class="header-anchor" href="#公開-url-還會直接打開成人圖片嗎" aria-label="Permalink to &quot;公開 URL 還會直接打開成人圖片嗎？&quot;">​</a></h3><p>如果目前存取模式不允許該分級，普通公開 URL 不會回傳原圖。</p><h3 id="隨機圖會抽到被限制的圖片嗎" tabindex="-1">隨機圖會抽到被限制的圖片嗎？ <a class="header-anchor" href="#隨機圖會抽到被限制的圖片嗎" aria-label="Permalink to &quot;隨機圖會抽到被限制的圖片嗎？&quot;">​</a></h3><p>不會。隨機圖會依目前存取模式過濾候選圖片。</p><h3 id="沒有分級的舊圖片會怎樣" tabindex="-1">沒有分級的舊圖片會怎樣？ <a class="header-anchor" href="#沒有分級的舊圖片會怎樣" aria-label="Permalink to &quot;沒有分級的舊圖片會怎樣？&quot;">​</a></h3><p>未分級圖片不會只因為沒有審查結果就自動隱藏。你可以之後在後台手動調整分級。</p>',63)])])}const q=e(d,[["render",o]]);export{m as __pageData,q as default};
